function About() {
  return (
    <section className="hero">
      <h1>Who Are We?</h1>

      <p>
        Community Help Hub is a platform that brings people together to support
        each other through volunteering, sharing skills, and offering services.
      </p>

      <p>
        We believe that small acts of kindness can make a big difference in our
        communities.
      </p>
    </section>
  );
}

export default About;
